#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int min(int a, int b) { return a < b ? a : b; }
int max(int a, int b) { return a > b ? a : b; }

int main() {
    int R, C, K, T, Z;
    scanf("%d %d", &R, &C);
    int **M = (int **)malloc(R * sizeof(int *));
    for (int i = 0; i < R; i++) {
        M[i] = (int *)malloc(C * sizeof(int));
        for (int j = 0; j < C; j++) {
            scanf("%d", &M[i][j]);
        }
    }
    scanf("%d", &K);
    for (int i = 0; i < K; i++) {
        int R1, C1, R2, C2, R3, C3, R4, C4;
        scanf("%d %d %d %d %d %d %d %d", &R1, &C1, &R2, &C2, &R3, &C3, &R4, &C4);
        // Compute minimum and maximum values in non-overlapping regions
        int min_val = INT_MAX, max_val = INT_MIN;
        for (int r = R1 - 1; r < R2; r++) {
            for (int c = C1 - 1; c < C2; c++) {
                if (!(r >= R3 - 1 && r < R4 && c >= C3 - 1 && c < C4)) {
                    min_val = min(min_val, M[r][c]);
                    max_val = max(max_val, M[r][c]);
                }
            }
        }
        for (int r = R3 - 1; r < R4; r++) {
            for (int c = C3 - 1; c < C4; c++) {
                if (!(r >= R1 - 1 && r < R2 && c >= C1 - 1 && c < C2)) {
                    min_val = min(min_val, M[r][c]);
                    max_val = max(max_val, M[r][c]);
                }
            }
        }
        printf("%d\n", max_val - min_val + 1);
    }
    scanf("%d", &T);
    scanf("%d", &Z);
    for (int i = 0; i < Z; i++) {
        int A, B;
        scanf("%d %d", &A, &B);
        // Calculate number of distinct ways to move in the square grid
        int **dp = (int **)malloc(T * sizeof(int *));
        for (int j = 0; j < T; j++) {
            dp[j] = (int *)malloc(T * sizeof(int));
            for (int k = 0; k < T; k++) {
                dp[j][k] = 0;
            }
        }
        dp[A - 1][B - 1] = 1;
        for (int j = 1; j <= T; j++) {
            for (int k = 0; k < T; k++) {
                for (int l = 0; l < T; l++) {
                    if (abs(k - l) <= j && k >= 0 && k < T && l >= 0 && l < T) {
                        dp[k][l] = (dp[k][l] + dp[k - 1][l]) % MOD;
                    }
                }
            }
        }
        printf("%d\n", dp[A - 1][B - 1]);
    }
    return 0;
}

